#include <stdio.h>
#include <stdlib.h>

int compare(const void *a, const void *b) {
    return (*(int*)a - *(int*)b);
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, K;
        scanf("%d %d", &N, &K);
        int arr[N + K];
        for (int i = 0; i < N; i++) {
            scanf("%d", &arr[i]);
        }
        for (int i = N; i < N + K; i++) {
            arr[i] = 1000;
        }
        qsort(arr, N + K, sizeof(int), compare);
        printf("%d\n", arr[(N + K) / 2]);
    }
    return 0;
}

