import java.util.Arrays;
import java.util.Scanner;

public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int K = sc.nextInt();
            int[] arr = new int[N + K];
            for (int i = 0; i < N; i++) {
                arr[i] = sc.nextInt();
            }
            for (int i = N; i < N + K; i++) {
                arr[i] = 1000;
            }
            Arrays.sort(arr);
            System.out.println(arr[(N + K) / 2]);
        }
    }
}

