const fs = require('fs');
const input = fs.readFileSync(0, 'utf-8').trim().split('\n');
let idx = 0;

function nextInt() {
    return parseInt(input[idx++]);
}

function nextIntArray() {
    return input[idx++].split(' ').map(x => parseInt(x));
}

let T = nextInt();
while (T-- > 0) {
    let [N, K] = nextIntArray();
    let arr = nextIntArray().concat(Array(K).fill(1000));
    arr.sort((a, b) => a - b);
    console.log(arr[(N + K) >> 1]);
}
